### 代码

```
	#include <iostream>

	using namespace std;

	int main()

	{

		int a[4],b[4];

		int i,j,tmp;

		for (i=0;i<4;i++)

			cin >> b[i];

		for (i=0;i<4;i++)

		{

			a[i]=0;

			for (j=0;j<=i;j++)

